1949	/// Build with debug info and launch cuda-gdb (or cgdb).
1950	///
1951	/// Compiles the example with `-C debuginfo=2` on top of the normal release
1952	/// flags, then launches the debugger on the resulting binary. Prints a
1953	/// quick-reference cheat sheet for common cuda-gdb commands before handing
1954	/// control to the debugger.
1955	pub fn codegen_debug(
1956	    ctx: &Context,
1957	    example: &str,
1958	    arch: Option<&str>,
1959	    features: Option<&str>,
1960	    bin: Option<&str>,
1961	    use_cgdb: bool,
1962	    use_tui: bool,
1963	) {
1964	    let cuda_gdb = find_cuda_toolkit_executable(
1965	        ctx,
1966	        "cuda-gdb",
1967	        &[
1968	            "/usr/local/cuda/bin/cuda-gdb",
1969	            "/opt/cuda/bin/cuda-gdb",
1970	            "/usr/bin/cuda-gdb",
1971	        ],
1972	    )
1973	    .unwrap_or_else(|| {
1974	        eprintln!("Error: cuda-gdb not found!");
1975	        eprintln!();
1976	        eprintln!("Make sure CUDA toolkit is installed and cuda-gdb is in your PATH");
1977	        eprintln!("or configured CUDA toolkit root:");
1978	        eprintln!("  export PATH=\"/usr/local/cuda/bin:$PATH\"");
1979	        eprintln!("  export CUDA_TOOLKIT_PATH=/usr/local/cuda");
1980	        std::process::exit(1);
1981	    });
1982	
1983	    let cgdb_path = if use_cgdb {
1984	        Some(find_executable("cgdb", &[]).unwrap_or_else(|| {
1985	            eprintln!("Error: cgdb not found!");
1986	            eprintln!("Install with: sudo apt install cgdb");
1987	            std::process::exit(1);
1988	        }))
1989	    } else {
1990	        None
1991	    };
1992	
1993	    let example_dir = if ctx.is_workspace {
1994	        resolve_example_dir(ctx, example)
1995	    } else {
1996	        ctx.workspace_root.clone()
1997	    };
1998	
1999	    let target_arch = configured_arch(ctx, arch);
2000	    let detected_device_arch = detect_run_target_arch(target_arch, false);
2001	
2002	    if let Some(bin) = bin {
2003	        println!("Building {} (bin: {}) with debug info...", example, bin);
2004	    } else {
2005	        println!("Building {} with debug info...", example);
2006	    }
2007	    if let Some(dev) = detected_device_arch.as_deref() {
2008	        println!("Detected GPU arch: {dev} (via nvidia-smi)");
2009	    }
2010	
2011	    clean_generated_files(&example_dir, example);
2012	
2013	    touch_main_rs(&example_dir);
2014	
2015	    let mut cmd = Command::new("cargo");
2016	    cmd.args(["build", "--release"]).current_dir(&example_dir);
2017	
2018	    if let Some(bin) = bin {
2019	        cmd.args(["--bin", bin]);
2020	    }
2021	    if let Some(features) = features {
2022	        cmd.args(["--features", features]);
2023	    }
2024	
2025	    apply_config_env(&mut cmd, ctx);
2026	    apply_codegen_rustflags(&mut cmd, ctx, true, &[]);
2027	    cmd.env("CARGO_PROFILE_RELEASE_DEBUG", "2");
2028	    apply_output_mode(&mut cmd, false, target_arch);
2029	    apply_device_arch_hint(&mut cmd, target_arch, detected_device_arch.as_deref());
2030	    apply_ld_library_path(&mut cmd, ctx);
2031	
2032	    let binary =
2033	        run_cargo_build_for_executable(&mut cmd, &example_dir, bin).unwrap_or_else(|message| {
2034	            eprintln!("Failed to build {example}: {message}");
2035	            std::process::exit(1);
2036	        });
2037	    if !binary.exists() {
2038	        eprintln!(
2039	            "Error: Cargo reported executable artifact {}, but it does not exist",
2040	            binary.display()
2041	        );
2042	        std::process::exit(1);
2043	    }
2044	
2045	    if cgdb_path.is_some() {
2046	        println!("Launching cgdb (cuda-gdb frontend)...");
2047	    } else {
2048	        println!(
2049	            "Launching cuda-gdb{}...",
2050	            if use_tui { " (TUI mode)" } else { "" }
2051	        );
2052	    }
2053	    println!();
2054	    println!("Quick reference:");
2055	    println!("  set cuda break_on_launch application");
2056	    println!("                           - Break at start of any kernel");
2057	    println!("  run                      - Start the program");
2058	    println!("  info cuda kernels        - List active kernels");
2059	    println!("  info cuda threads        - List GPU threads");
2060	    println!("  cuda thread (0,0,0)      - Switch to thread");
2061	    println!("  cuda block (0,0,0)       - Switch to block");
2062	    println!("  print <var>              - Print variable");
2063	    println!("  next / step / continue   - Execution control");
2064	    println!("  quit                     - Exit debugger");
2065	    if cgdb_path.is_some() {
2066	        println!();
2067	        println!("cgdb shortcuts:");
2068	        println!("  Esc                      - Focus source window (vim keys work)");
2069	        println!("  i                        - Focus command window");
2070	        println!("  space                    - Set breakpoint on current line");
2071	        println!("  o                        - Open file dialog");
2072	    } else if use_tui {
2073	        println!();
2074	        println!("TUI shortcuts:");
2075	        println!("  Ctrl+x a                 - Toggle TUI mode");
2076	        println!("  Ctrl+x 2                 - Split view (source + asm)");
2077	        println!("  Ctrl+l                   - Refresh screen");
2078	    }
2079	    println!();
2080	
2081	    let status = if let Some(cgdb) = cgdb_path {
2082	        Command::new(cgdb)
2083	            .arg("-d")
2084	            .arg(&cuda_gdb)
2085	            .arg(&binary)
2086	            .current_dir(&example_dir)
2087	            .status()
2088	            .expect("Failed to launch cgdb")
2089	    } else {
2090	        let mut gdb_cmd = Command::new(&cuda_gdb);
2091	        if use_tui {
2092	            gdb_cmd.arg("--tui");
2093	        }
2094	        gdb_cmd.arg(&binary);
2095	        gdb_cmd.current_dir(&example_dir);
2096	        gdb_cmd.status().expect("Failed to launch cuda-gdb")
2097	    };
2098	
2099	    if !status.success() {
2100	        std::process::exit(status.code().unwrap_or(1));
2101	    }
2102	}
